class MKAverage {
public:
    MKAverage(int m, int k) {
        this->m = m;
        this->k = k;
        this->nums = vector<int>();
    }

    void addElement(int num) {
        nums.push_back(num);
        if (nums.size() > m) {
            nums.erase(nums.begin());
        }
    }

    int calculateMKAverage() {
        if (nums.size() < m) {
            return -1;
        }
        sort(nums.begin(), nums.end());
        nums.erase(nums.begin() + k, nums.begin() + k + 1);
        nums.erase(nums.end() - k, nums.end());
        int sum = 0;
        for (int num : nums) {
            sum += num;
        }
        return sum / (nums.size() - 2 * k);
    }

private:
    int m;
    int k;
    vector<int> nums;
};
```
